{% extends "base.html" %}

{% block title %}Chat{% endblock %}

{% block content %}
<div class="container mx-auto px-4 py-8 max-w-xl">
    <h1 class="text-2xl font-bold mb-6 text-center">Ollama Chat</h1>
    <div id="chat-log"
         class="mt-4 flex-1 overflow-y-auto p-4 bg-white rounded-md shadow-md mb-4"
         hx-ws-on::message="
             const messageDiv = document.createElement('div');
             messageDiv.className = 'mb-2';
             if (event.detail.token) {
                 // If it's a token, append to the last message div if it's from the assistant
                 const lastDiv = this.lastElementChild;
                 if (lastDiv && lastDiv.classList.contains('assistant-message')) {
                     lastDiv.append(document.createTextNode(event.detail.token));
                 } else {
                     messageDiv.className = 'assistant-message mb-2';
                     messageDiv.append(document.createTextNode(event.detail.token));
                     this.appendChild(messageDiv);
                 }
             } else if (event.detail.message) {
                 // If it's a full message (user message), display it
                 messageDiv.className = 'user-message mb-2 text-right';
                 messageDiv.textContent = event.detail.message;
                 this.appendChild(messageDiv);
             }
             this.scrollTop = this.scrollHeight;
         ">
    </div>
    <form id="chat-form"
          hx-ws="connect:ws/chat/"
          hx-ws-send="submit"
          hx-trigger="submit"
          class="flex">
        <input name="message" type="text"
               class="flex-1 border border-gray-300 rounded-l-md p-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
               placeholder="Type a message..."
               required>
        <button type="submit"
                class="bg-blue-500 text-white px-4 py-2 rounded-r-md hover:bg-blue-600">
            Send
        </button>
    </form>
</div>
{% endblock %}

